args.sparql:
SELECT ?superbowlLabel WHERE {
  wd:Q458000 wdt:P175 ?superbowl .
  ?superbowl rdfs:label ?superbowlLabel .
  FILTER (LANG(?superbowlLabel) = 'en' && CONTAINS(STR(?superbowlLabel), 'Super Bowl XXXVI'))
}

SELECT ?performerLabel WHERE {
  wd:Q1073479 p:P175 ?statement .
  ?statement ps:P175 ?performer .
  ?performer rdfs:label ?performerLabel .
  FILTER (LANG(?performerLabel) = 'en')
}
